const own = $('Set Keyword + Target').first().json.ownDomain;
const results = $json.organic_results || [];
let ownRank = null;
const competitors = [];
for (const r of results) {
  if (!r.link) continue;
  if (r.link.includes(own)) { if (ownRank===null) ownRank = r.position; }
  else competitors.push(r.link);
}
return [{ json: {
  keyword: $('Set Keyword + Target').first().json.keyword,
  targetPage: $('Set Keyword + Target').first().json.targetPage,
  ownRank,
  topCompetitor: competitors[0] || null,
  competitors: competitors.slice(0,3)
}}];

const html = $json.data || $json.body || '';
const pick = (re) => { const m = html.match(re); return m ? m[1].replace(/<[^>]+>/g,'').trim() : ''; };
const title = pick(/<title[^>]*>([\s\S]*?)<\/title>/i);
const meta = pick(/<meta[^>]*name=["']description["'][^>]*content=["']([^"']*)/i);
const h2s = [...html.matchAll(/<h2[^>]*>([\s\S]*?)<\/h2>/gi)].map(m=>m[1].replace(/<[^>]+>/g,'').trim()).slice(0,10);
const words = html.replace(/<[^>]+>/g,' ').split(/\s+/).filter(Boolean).length;
const prev = $('Parse Rank + Competitors').first().json;
return [{ json: { ...prev, comp_title: title, comp_meta: meta, comp_h2: h2s, comp_words: words }}];

