let rec; try { rec = JSON.parse(txt.replace(/```json|```/g,'').trim()); } catch(e){ rec = { _raw: txt }; }
const prev = $('Extract Competitor On-Page').first().json;
return [{ json: { keyword: prev.keyword, ownRank: prev.ownRank, topCompetitor: prev.topCompetitor, recommendation: rec }}];
